{
var mode = GetChoice(parameters, "mode", "extractRed");
var levels = GetInt(parameters, "posterizeLevels", 4);
var keepAlpha = GetBool(parameters, "keepAlpha", true);

var size = context.TileSize;
var result = new PixelBuffer(size, size);

var src = inputs.Length > 0 ? inputs[0] : null;

if (mode == "combineRGBA")
{
    var rChannel = inputs.Length > 1 ? inputs[1] : null;
    var gChannel = inputs.Length > 2 ? inputs[2] : null;
    var bChannel = inputs.Length > 3 ? inputs[3] : null;
    var aChannel = inputs.Length > 4 ? inputs[4] : null;

    result.ParallelForEachPixel((x, y) =>
    {
        float ra = 0, ga = 0, ba = 0, aa = 1;
        if (rChannel != null) (ra, _, _, _) = rChannel.GetPixel(x, y);
        if (gChannel != null) (_, ga, _, _) = gChannel.GetPixel(x, y);
        if (bChannel != null) (_, _, ba, _) = bChannel.GetPixel(x, y);
        if (aChannel != null) (_, _, _, aa) = aChannel.GetPixel(x, y);
        result.SetPixel(x, y, ra, ga, ba, aa);
    });
}
else if (mode == "grayscale")
{
    result.ParallelForEachPixel((x, y) =>
    {
        if (src != null)
        {
            var (r, g, b, a) = src.GetPixel(x, y);
            var gray = 0.299f * r + 0.587f * g + 0.114f * b;
            result.SetPixel(x, y, gray, gray, gray, keepAlpha ? a : 1f);
        }
    });
}
else if (mode == "invertColors")
{
    result.ParallelForEachPixel((x, y) =>
    {
        if (src != null)
        {
            var (r, g, b, a) = src.GetPixel(x, y);
            result.SetPixel(x, y, 1f - r, 1f - g, 1f - b, keepAlpha ? a : 1f);
        }
    });
}
else if (mode == "posterize")
{
    var step = 1f / levels;
    result.ParallelForEachPixel((x, y) =>
    {
        if (src != null)
        {
            var (r, g, b, a) = src.GetPixel(x, y);
            r = MathF.Round(r / step) * step;
            g = MathF.Round(g / step) * step;
            b = MathF.Round(b / step) * step;
            result.SetPixel(x, y, r, g, b, keepAlpha ? a : 1f);
        }
    });
}
else
{
    // Channel extraction
    int channelIndex = mode switch
    {
        "extractRed" => 0,
        "extractGreen" => 1,
        "extractBlue" => 2,
        "extractAlpha" => 3,
        _ => 0
    };

    result.ParallelForEachPixel((x, y) =>
    {
        if (src != null)
        {
            var (r, g, b, a) = src.GetPixel(x, y);
            float val = channelIndex switch
            {
                0 => r, 1 => g, 2 => b, 3 => a, _ => r
            };
            result.SetPixel(x, y, val, val, val, 1f);
        }
    });
}

return result;
}
